+        ApiFamily::Stdlib,
+        nptr as usize,
+        0,
+        false,
+        known_remaining(nptr as usize).is_none(),
+        0,
+    );
+    if matches!(decision.action, MembraneAction::Deny) {
+        runtime_policy::observe(ApiFamily::Stdlib, decision.profile, 6, true);
+        return 0;
