+    };
+
+    let (len, _terminated) = unsafe { scan_c_string(nptr, bound) };
+    let slice = unsafe { std::slice::from_raw_parts(nptr as *const u8, len) };
+    let result = glibc_rs_core::stdlib::atoi(slice);
