+    match bound {
+        Some(limit) => {
+            for i in 0..limit {
+                // SAFETY: caller provides validity for bounded read.
+                if unsafe { *ptr.add(i) } == 0 {
+                    return (i, true);
+                }
+            }
+            (limit, false)
+        }
+        None => {
+            let mut i = 0usize;
